    int maxSatisfied(vector<int>& customers, vector<int>& grumpy, int minutes) {
        int satisfied = 0;
        int maxSatisfied = 0;
        int windowStart = 0;
        int currentGrumpy = 0;
        for (int windowEnd = 0; windowEnd < customers.size(); windowEnd++) {
            if (grumpy[windowEnd] == 1) {
                currentGrumpy++;
            }
            if (windowEnd - windowStart + 1 == minutes) {
                satisfied -= customers[windowStart] * currentGrumpy;
                windowStart++;
                currentGrumpy--;
            }
            maxSatisfied = max(maxSatisfied, satisfied + (int)accumulate(customers.begin() + windowStart, customers.begin() + windowEnd + 1, 0));
        }
        return maxSatisfied;
    }
};
